import { useEffect } from 'react';
import { ErrorBoundary } from './components/ErrorBoundary';
import { useAppState } from './hooks/useAppState';
import HomeView from './components/HomeView';
import SessionsView from './components/SessionsView';
import ProfileView from './components/ProfileView';
import { deviceControls } from './lib/deviceControls';
import { Capacitor } from '@capacitor/core';

type TabType = 'home' | 'sessions' | 'history' | 'profile';

function App() {
  const {
    activeTab,
    setActiveTab,
    isPlaying,
    currentSession,
    togglePlayback
  } = useAppState();

  // Initialize device controls
  useEffect(() => {
    deviceControls.updateNowPlaying(currentSession, isPlaying);

    // Set up media session handlers
    if ('mediaSession' in navigator) {
      navigator.mediaSession.setActionHandler('play', async () => {
        await togglePlayback();
      });

      navigator.mediaSession.setActionHandler('pause', async () => {
        await togglePlayback();
      });

      navigator.mediaSession.setActionHandler('stop', async () => {
        await togglePlayback();
      });
    }
  }, [currentSession, togglePlayback]);

  // Update playback state
  useEffect(() => {
    if ('mediaSession' in navigator) {
      navigator.mediaSession.playbackState = isPlaying ? 'playing' : 'paused';
    }
  }, [isPlaying]);

  const tabs: Array<{ id: TabType; label: string; icon: string }> = [
    { id: 'home', label: 'Home', icon: '🏠' },
    { id: 'sessions', label: 'Sessions', icon: '📚' },
    { id: 'history', label: 'History', icon: '📊' },
    { id: 'profile', label: 'Profile', icon: '⚙️' }
  ];

  const renderView = () => {
    switch (activeTab) {
      case 'home':
        return <HomeView />;
      case 'sessions':
        return <SessionsView />;
      case 'history':
        // History is shown as a modal from ProfileView
        return <ProfileView initialShowHistory />;
      case 'profile':
        return <ProfileView />;
      default:
        return <HomeView />;
    }
  };

  return (
    <ErrorBoundary>
      <div className="h-screen w-screen overflow-hidden bg-gradient-to-b from-indigo-900 via-purple-900 to-indigo-900">
        {/* Main Content */}
        <div className="h-full pb-20 safe-area-inset">
          {renderView()}
        </div>

        {/* Bottom Tab Navigation */}
        <div className="fixed bottom-0 left-0 right-0 bg-black/40 backdrop-blur-xl border-t border-white/10 safe-area-inset-bottom">
          <div className="flex items-center justify-around h-16 sm:h-20 px-2">
            {tabs.map((tab) => {
              const isActive = activeTab === tab.id;
              return (
                <button
                  key={tab.id}
                  onClick={() => {
                    setActiveTab(tab.id);
                    if (Capacitor.getPlatform() === 'ios') {
                      import('@capacitor/haptics').then(({ Haptics }) => {
                        Haptics.selectionChanged().catch(() => {});
                      });
                    }
                  }}
                  className={`flex flex-col items-center justify-center flex-1 h-full transition-colors ${
                    isActive
                      ? 'text-purple-400'
                      : 'text-purple-200/60'
                  }`}
                  aria-label={tab.label}
                >
                  <span className="text-2xl mb-1">{tab.icon}</span>
                  <span className="text-xs font-medium">{tab.label}</span>
                  {isActive && (
                    <div className="absolute bottom-0 left-0 right-0 h-1 bg-gradient-to-r from-blue-500 to-purple-600 rounded-t-full" />
                  )}
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </ErrorBoundary>
  );
}

export default App;

