  --primary-bg-start: #1c1c3c;
  --primary-bg-end: #3c1c5c;
  --accent-golden: #DAA520;
  --primary-blue: #3B82F6;
  --secondary-pink: #FF69B4;
  --neutral-white: #FFFFFF;
  --neutral-light-grey: #E5E7EB;
  --neutral-dark-grey: #D3D3D3;
  --text-grey-300: #D1D5DB;
  --text-grey-400: #9CA3AF;
  --card-bg: rgba(17, 24, 39, 0.5);
  --border-grey: #374151;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: var(--font-family-primary);
  background: var(--color-bg-primary);
  min-height: 100vh;
  min-height: -webkit-fill-available; /* iOS Safari fix */
  color: var(--color-text-primary);
  overflow-x: hidden;
  /* Safe area support for iPhone XR and newer devices with notch */
  padding-top: env(safe-area-inset-top);
  padding-bottom: env(safe-area-inset-bottom);
  padding-left: env(safe-area-inset-left);
  padding-right: env(safe-area-inset-right);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

#root {
  width: 100%;
  min-height: 100vh;
  min-height: -webkit-fill-available; /* iOS Safari fix */
  display: flex;
  flex-direction: column;
  /* Safe area support */
  padding-top: env(safe-area-inset-top);
  padding-bottom: env(safe-area-inset-bottom);
  padding-left: env(safe-area-inset-left);
  padding-right: env(safe-area-inset-right);
}

/* Safe Area Support for iPhone XR and newer devices */
.safe-area-inset {
  padding-top: max(env(safe-area-inset-top), 0.5rem);
  padding-bottom: max(env(safe-area-inset-bottom), 0.5rem);
  padding-left: max(env(safe-area-inset-left), 0.75rem);
  padding-right: max(env(safe-area-inset-right), 0.75rem);
}

@media (min-width: 640px) {
  .safe-area-inset {
    padding-top: max(env(safe-area-inset-top), 1rem);
    padding-bottom: max(env(safe-area-inset-bottom), 1rem);
    padding-left: max(env(safe-area-inset-left), 1rem);
    padding-right: max(env(safe-area-inset-right), 1rem);
  }
}

