    radial-gradient(2px 2px at 45% 55%, rgba(192, 192, 192, 0.4), transparent),
    radial-gradient(1px 1px at 55% 45%, rgba(192, 192, 192, 0.3), transparent),
    radial-gradient(2px 2px at 5% 35%, rgba(192, 192, 192, 0.5), transparent),
    radial-gradient(1px 1px at 95% 65%, rgba(192, 192, 192, 0.4), transparent),
    radial-gradient(1px 1px at 35% 5%, rgba(192, 192, 192, 0.3), transparent),
