    radial-gradient(1px 1px at 12% 50%, rgba(192, 192, 192, 0.4), transparent),
    radial-gradient(2px 2px at 88% 50%, rgba(192, 192, 192, 0.3), transparent),
    radial-gradient(1px 1px at 50% 12%, rgba(192, 192, 192, 0.4), transparent),
    radial-gradient(1px 1px at 50% 88%, rgba(192, 192, 192, 0.3), transparent),
