import React, { useState, useEffect, useRef } from 'react';
import { useAppState } from '../hooks/useAppState';
import { Haptics, ImpactStyle } from '@capacitor/haptics';
import { Capacitor } from '@capacitor/core';

const HomeView: React.FC = () => {
  const {
    isPlaying,
    currentSession,
    settings,
    togglePlayback,
    updateSettings,
    audioEngine,
    handleSessionComplete,
    setActiveTab
  } = useAppState();

  const [timeRemaining, setTimeRemaining] = useState(0);
  const [progress, setProgress] = useState(0);
  const animationRef = useRef<number>();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const isIOS = Capacitor.getPlatform() === 'ios';

  // Session timer
  useEffect(() => {
    // #region agent log
    fetch('http://127.0.0.1:7242/ingest/54a371b5-26d0-4fda-a7dc-6c2519cd2d1c',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'HomeView.tsx:25',message:'Timer effect started',data:{isPlaying,hasSession:!!currentSession},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'C'})}).catch(()=>{});
    // #endregion
    if (isPlaying && currentSession) {
      const startTime = Date.now();
      const duration = (currentSession.lengths[0] || 30) * 60 * 1000;

      const updateTimer = () => {
        const elapsed = Date.now() - startTime;
        const remaining = Math.max(0, duration - elapsed);
        const seconds = Math.floor(remaining / 1000);
        setTimeRemaining(seconds);
        setProgress((elapsed / duration) * 100);

        if (remaining > 0) {
          animationRef.current = requestAnimationFrame(updateTimer);
        } else {
          handleSessionComplete();
        }
      };

      animationRef.current = requestAnimationFrame(updateTimer);
    } else {
      setTimeRemaining(0);
      setProgress(0);
    }

    return () => {
      // #region agent log
      fetch('http://127.0.0.1:7242/ingest/54a371b5-26d0-4fda-a7dc-6c2519cd2d1c',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'HomeView.tsx:50',message:'Timer cleanup',data:{hasAnimationRef:!!animationRef.current},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'C'})}).catch(()=>{});
      // #endregion
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, [isPlaying, currentSession, handleSessionComplete]);

  // Audio visualization
  useEffect(() => {
    // #region agent log
    fetch('http://127.0.0.1:7242/ingest/54a371b5-26d0-4fda-a7dc-6c2519cd2d1c',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'HomeView.tsx:58',message:'Visualization effect started',data:{isPlaying,hasCanvas:!!canvasRef.current},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'C'})}).catch(()=>{});
    // #endregion
    if (!isPlaying || !canvasRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);

    const width = rect.width;
    const height = rect.height;

    const draw = () => {
      if (!isPlaying || !ctx) return;

      const data = audioEngine.getAnalyserData();
      if (!data || data.length === 0) {
        animationRef.current = requestAnimationFrame(draw);
        return;
      }

      // Clear canvas
      ctx.fillStyle = 'rgba(0, 0, 0, 0.1)';
      ctx.fillRect(0, 0, width, height);

      // Draw waveform
      ctx.strokeStyle = '#a78bfa';
      ctx.lineWidth = 2;
      ctx.beginPath();

      const sliceWidth = width / data.length;
      const centerY = height / 2;
      let x = 0;

      for (let i = 0; i < data.length; i++) {
        const v = data[i] / 128.0;
        const y = v * height * 0.3 + centerY;

        if (i === 0) {
          ctx.moveTo(x, y);
        } else {
          ctx.lineTo(x, y);
        }

        x += sliceWidth;
      }

      ctx.stroke();
      animationRef.current = requestAnimationFrame(draw);
    };

    animationRef.current = requestAnimationFrame(draw);

    return () => {
      // #region agent log
      fetch('http://127.0.0.1:7242/ingest/54a371b5-26d0-4fda-a7dc-6c2519cd2d1c',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'HomeView.tsx:115',message:'Visualization cleanup',data:{hasAnimationRef:!!animationRef.current},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'C'})}).catch(()=>{});
      // #endregion
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, [isPlaying, audioEngine]);

  const formatTime = (seconds: number): string => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handlePlayPause = async () => {
    await togglePlayback();
    if (isIOS) {
      Haptics.impact({ style: ImpactStyle.Medium }).catch(() => {});
    }
  };

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const volume = parseFloat(e.target.value);
    updateSettings({ ...settings, volume });
    if (isIOS) {
      Haptics.impact({ style: ImpactStyle.Light }).catch(() => {});
    }
  };

  const quickStartGoals = [
    { goal: 'sleep' as const, emoji: '😴', label: 'Sleep', color: 'from-indigo-500 to-purple-600' },
    { goal: 'focus' as const, emoji: '🧠', label: 'Focus', color: 'from-blue-500 to-cyan-600' },
    { goal: 'meditation' as const, emoji: '🧘', label: 'Meditate', color: 'from-purple-500 to-pink-600' },
    { goal: 'anxiety' as const, emoji: '😌', label: 'Relax', color: 'from-teal-500 to-emerald-600' }
  ];

  return (
    <div className="flex flex-col h-full bg-gradient-to-b from-indigo-900 via-purple-900 to-indigo-900 p-4 sm:p-6 safe-area-inset">
      {/* Header */}
      <div className="mb-6 sm:mb-8">
        <h1 className="text-3xl sm:text-4xl font-bold text-white mb-2">Blue Star Beats</h1>
        <p className="text-purple-200 text-sm sm:text-base">Precision Brainwave Entrainment</p>
      </div>

      {/* Quick Start Cards */}
      {!currentSession && (
        <div className="grid grid-cols-2 gap-3 sm:gap-4 mb-6 sm:mb-8">
          {quickStartGoals.map((item) => (
            <button
              key={item.goal}
              className="bg-white/10 backdrop-blur-lg rounded-2xl p-4 sm:p-6 border border-white/20 active:scale-95 transition-transform"
              onClick={() => {
                if (isIOS) {
                  Haptics.impact({ style: ImpactStyle.Light }).catch(() => {});
                }
                setActiveTab('sessions');
              }}
            >
              <div className={`w-12 h-12 sm:w-16 sm:h-16 bg-gradient-to-r ${item.color} rounded-xl mb-3 flex items-center justify-center text-2xl sm:text-3xl`}>
                {item.emoji}
              </div>
              <h3 className="text-white font-semibold text-sm sm:text-base">{item.label}</h3>
            </button>
          ))}
        </div>
      )}

      {/* Now Playing Section */}
      {currentSession && (
        <div className="bg-white/10 backdrop-blur-lg rounded-3xl p-4 sm:p-6 border border-white/20 mb-6">
          <div className="flex items-center justify-between mb-4">
            <div className="flex-1">
              <h2 className="text-xl sm:text-2xl font-bold text-white mb-1">{currentSession.name}</h2>
              <p className="text-purple-200 text-sm">{currentSession.description}</p>
            </div>
            <div className="text-right ml-4">
              <div className="text-2xl sm:text-3xl font-bold text-white">{formatTime(timeRemaining)}</div>
              <div className="text-xs sm:text-sm text-purple-200">remaining</div>
            </div>
          </div>

          {/* Visualization */}
          <div className="h-24 sm:h-32 mb-4 sm:mb-6 rounded-xl bg-black/20 overflow-hidden relative">
            <canvas
              ref={canvasRef}
              className="w-full h-full"
              style={{ width: '100%', height: '100%' }}
            />
            {!isPlaying && (
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-12 h-12 sm:w-16 sm:h-16 rounded-full bg-gradient-to-r from-blue-400 to-purple-500 animate-pulse opacity-50"></div>
              </div>
            )}
          </div>

          {/* Progress Circle */}
          <div className="flex justify-center mb-4 sm:mb-6">
            <div className="relative w-24 h-24 sm:w-32 sm:h-32">
              <svg className="w-full h-full" viewBox="0 0 100 100">
                <circle
                  cx="50"
                  cy="50"
                  r="45"
                  fill="none"
                  stroke="rgba(255, 255, 255, 0.2)"
                  strokeWidth="8"
                />
                <circle
                  cx="50"
                  cy="50"
                  r="45"
                  fill="none"
                  stroke="url(#gradient)"
                  strokeWidth="8"
                  strokeLinecap="round"
                  strokeDasharray="283"
                  strokeDashoffset={283 - (283 * progress) / 100}
                  transform="rotate(-90 50 50)"
                />
                <defs>
                  <linearGradient id="gradient" x1="0%" y1="0%" x2="100%" y2="0%">
                    <stop offset="0%" stopColor="#60a5fa" />
                    <stop offset="100%" stopColor="#a78bfa" />
                  </linearGradient>
                </defs>
              </svg>
              <div className="absolute inset-0 flex items-center justify-center">
                <span className="text-white text-base sm:text-lg font-bold">
                  {Math.round(progress)}%
                </span>
              </div>
            </div>
          </div>

          {/* Controls */}
          <div className="flex items-center justify-between">
            <button
              className="w-14 h-14 sm:w-16 sm:h-16 rounded-full bg-gradient-to-r from-blue-500 to-purple-600 flex items-center justify-center shadow-lg active:scale-95 transition-transform"
              onClick={handlePlayPause}
              aria-label={isPlaying ? 'Pause' : 'Play'}
            >
              {isPlaying ? (
                <div className="w-5 h-5 sm:w-6 sm:h-6 bg-white rounded-sm"></div>
              ) : (
                <div className="w-0 h-0 border-l-[6px] sm:border-l-[8px] border-l-white border-y-[4px] sm:border-y-[6px] border-y-transparent ml-1"></div>
              )}
            </button>

            <div className="flex-1 mx-4">
              <input
                type="range"
                min="0"
                max="1"
                step="0.01"
                value={settings.volume}
                onChange={handleVolumeChange}
                className="w-full h-2 bg-white/20 rounded-lg appearance-none cursor-pointer accent-purple-500"
              />
            </div>

            <div className="text-white font-medium text-sm sm:text-base min-w-[3rem] text-right">
              {Math.round(settings.volume * 100)}%
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default HomeView;

SessionsView.tsx.content:
import React, { useState, useMemo } from 'react';
import { useAppState } from '../hooks/useAppState';
import { SESSION_PROTOCOLS, getSessionsByGoal } from '../lib/sessionProtocols';
import { GoalType, SessionLength } from '../lib/sessionProtocols';
import { Haptics, ImpactStyle } from '@capacitor/haptics';
import { Capacitor } from '@capacitor/core';
import { premiumService } from '../lib/premiumService';
import { userPreferences } from '../lib/userPreferences';
import { SessionRecommendationEngine } from '../lib/sessionRecommendations';

const SessionsView: React.FC = () => {
  const { selectSession } = useAppState();
  const [searchQuery, setSearchQuery] = useState('');
  const [filter, setFilter] = useState<'all' | GoalType>('all');
  const isIOS = Capacitor.getPlatform() === 'ios';
  const isPremium = premiumService.isPremium();

  const categories: Array<'all' | GoalType> = ['all', 'sleep', 'focus', 'meditation', 'anxiety'];

  // Get recommended sessions
  const recommendedSessions = useMemo(() => {
    if (filter !== 'all') {
      return SessionRecommendationEngine.recommendSessions(filter, 3);
    }
    return [];
  }, [filter]);

  const filteredSessions = useMemo(() => {
    let sessions = filter === 'all' 
      ? SESSION_PROTOCOLS.filter(s => !s.isPremium || isPremium)
      : getSessionsByGoal(filter, isPremium);

    // Filter by search
    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase();
      sessions = sessions.filter(session =>
        session.name.toLowerCase().includes(query) ||
        session.description.toLowerCase().includes(query)
      );
    }

    return sessions;
  }, [searchQuery, filter, isPremium]);

  const handleSessionSelect = (session: typeof SESSION_PROTOCOLS[0]) => {
    const length = session.lengths[0] || 30;
    selectSession(session, length as SessionLength);
    if (isIOS) {
      Haptics.impact({ style: ImpactStyle.Medium }).catch(() => {});
    }
  };

  const favorites = userPreferences.loadPreferences().favoriteSessions;
  const favoriteSessions = SESSION_PROTOCOLS.filter(s => 
    favorites.includes(s.id) && (!s.isPremium || isPremium)
  );

  return (
    <div className="flex flex-col h-full bg-gradient-to-b from-indigo-900 via-purple-900 to-indigo-900 p-4 sm:p-6 safe-area-inset">
      {/* Header */}
      <div className="mb-4 sm:mb-6">
        <h1 className="text-2xl sm:text-3xl font-bold text-white mb-4">Sessions</h1>

        {/* Search */}
        <div className="relative mb-4">
          <input
            type="text"
            placeholder="Search sessions..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-white/10 backdrop-blur-lg rounded-xl py-3 px-4 pr-12 text-white placeholder-purple-200 border border-white/20 focus:border-purple-400 focus:outline-none text-sm sm:text-base"
          />
          <div className="absolute right-3 top-3.5 text-purple-300">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" />
            </svg>
          </div>
        </div>

        {/* Category Filters */}
        <div className="flex space-x-2 mb-4 overflow-x-auto pb-2 scrollbar-hide">
          {categories.map(category => (
            <button
              key={category}
              className={`px-4 py-2 rounded-full text-sm whitespace-nowrap transition-colors ${
                filter === category
                  ? 'bg-purple-600 text-white shadow-lg'
                  : 'bg-white/10 text-purple-200 hover:bg-white/20'
              }`}
              onClick={() => {
                setFilter(category);
                if (isIOS) {
                  Haptics.selectionChanged().catch(() => {});
                }
              }}
            >
              {category.charAt(0).toUpperCase() + category.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {/* Recommended Section */}
      {recommendedSessions.length > 0 && filter !== 'all' && (
        <div className="mb-4">
          <h2 className="text-sm font-semibold text-purple-200 mb-2 flex items-center gap-2">
            <span>✨</span> Recommended for You
          </h2>
          <div className="space-y-2">
            {recommendedSessions.map(session => {
              const stats = userPreferences.getSessionStats(session.id);
              return (
                <div
                  key={session.id}
                  className="bg-white/10 backdrop-blur-lg rounded-xl p-3 border border-purple-500/30 active:scale-[0.98] transition-transform"
                  onClick={() => handleSessionSelect(session)}
                >
                  <div className="flex items-center justify-between">
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="text-white font-semibold text-sm">{session.name}</h3>
                        {userPreferences.isFavorite(session.id) && (
                          <span className="text-yellow-400 text-xs">⭐</span>
                        )}
                      </div>
                      {stats.count > 0 && (
                        <p className="text-xs text-purple-300">
                          Played {stats.count}x {stats.averageRating && `• ${stats.averageRating.toFixed(1)}⭐`}
                        </p>
                      )}
                    </div>
                    <div className="w-8 h-8 rounded-full bg-gradient-to-r from-blue-400 to-purple-500 flex items-center justify-center ml-2">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-white" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
                      </svg>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Favorites Section */}
      {favoriteSessions.length > 0 && filter === 'all' && (
        <div className="mb-4">
          <h2 className="text-sm font-semibold text-purple-200 mb-2 flex items-center gap-2">
            <span>⭐</span> Favorites
          </h2>
          <div className="space-y-2">
            {favoriteSessions.slice(0, 3).map(session => (
              <div
                key={session.id}
                className="bg-white/10 backdrop-blur-lg rounded-xl p-3 border border-yellow-500/30 active:scale-[0.98] transition-transform"
                onClick={() => handleSessionSelect(session)}
              >
                <div className="flex items-center justify-between">
                  <div className="flex-1">
                    <h3 className="text-white font-semibold text-sm">{session.name}</h3>
                    <p className="text-xs text-purple-300 mt-1">{session.description}</p>
                  </div>
                  <div className="w-8 h-8 rounded-full bg-gradient-to-r from-yellow-400 to-orange-500 flex items-center justify-center ml-2">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-white" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
                    </svg>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Session List */}
      <div className="flex-1 overflow-y-auto">
        {filteredSessions.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-center py-12">
            <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center mb-4">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-purple-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <h3 className="text-lg font-medium text-white mb-2">No sessions found</h3>
            <p className="text-purple-200 text-sm">Try adjusting your search or filter</p>
            {!isPremium && (
              <p className="text-purple-300 text-xs mt-2">Upgrade to Premium for more sessions</p>
            )}
          </div>
        ) : (
          <div className="space-y-3">
            {filteredSessions.map(session => {
              const stats = userPreferences.getSessionStats(session.id);
              return (
                <div
                  key={session.id}
                  className="bg-white/10 backdrop-blur-lg rounded-2xl p-4 border border-white/20 active:scale-[0.98] transition-transform cursor-pointer"
                  onClick={() => handleSessionSelect(session)}
                >
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <div className="flex items-center mb-1">
                        <h3 className="text-white font-semibold text-base sm:text-lg mr-2">{session.name}</h3>
                        {userPreferences.isFavorite(session.id) && (
                          <span className="text-yellow-400 text-sm">⭐</span>
                        )}
                        {session.isPremium && (
                          <span className="bg-gradient-to-r from-yellow-400 to-orange-500 text-xs text-black px-2 py-0.5 rounded-full font-bold ml-2">
                            PRO
                          </span>
                        )}
                      </div>
                      <p className="text-purple-200 text-sm mb-2 line-clamp-2">{session.description}</p>
                      <div className="flex items-center text-xs text-purple-300 flex-wrap gap-2">
                        <span className="capitalize">{session.goal}</span>
                        <span>•</span>
                        <span>{session.lengths.join(', ')} min</span>
                        {stats.count > 0 && (
                          <>
                            <span>•</span>
                            <span>Played {stats.count}x</span>
                            {stats.averageRating && (
                              <>
                                <span>•</span>
                                <span className="flex items-center gap-1">
                                  <span>⭐</span>
                                  {stats.averageRating.toFixed(1)}
                                </span>
                              </>
                            )}
                          </>
                        )}
                      </div>
                    </div>
                    <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-full bg-gradient-to-r from-blue-400 to-purple-500 flex items-center justify-center ml-3 flex-shrink-0">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 sm:h-6 sm:w-6 text-white" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
                      </svg>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

export default SessionsView;

ProfileView.tsx.content:
import React, { useState, useEffect } from 'react';
import { useAppState } from '../hooks/useAppState';
import { premiumService } from '../lib/premiumService';
import { userPreferences } from '../lib/userPreferences';
import { Haptics, ImpactStyle, NotificationType } from '@capacitor/haptics';
import { Capacitor } from '@capacitor/core';
import { AUDIO_PRESETS } from '../lib/audioPresets';
import { AudioPreset } from '../lib/types';
import SessionHistory from './SessionHistory';
import PremiumModal from './PremiumModal';

interface ProfileViewProps {
  initialShowHistory?: boolean;
}

const ProfileView: React.FC<ProfileViewProps> = ({ initialShowHistory = false }) => {
  const { settings, updateSettings } = useAppState();
  const [showHistory, setShowHistory] = useState(initialShowHistory);

  useEffect(() => {
    if (initialShowHistory) {
      setShowHistory(true);
    }
  }, [initialShowHistory]);
  const [showPremiumModal, setShowPremiumModal] = useState(false);
  const [showPresets, setShowPresets] = useState(false);
  const isIOS = Capacitor.getPlatform() === 'ios';
  const isPremium = premiumService.isPremium();
  const history = userPreferences.getSessionHistory();

  const stats = {
    totalSessions: history.length,
    completedSessions: history.filter(e => e.completed).length,
    totalDuration: history.filter(e => e.completed).reduce((sum, e) => sum + e.duration, 0),
    averageRating: (() => {
      const ratings = history
        .map(e => e.effectivenessRating)
        .filter((r): r is number => r !== undefined);
      return ratings.length > 0
        ? ratings.reduce((sum, r) => sum + r, 0) / ratings.length
        : 0;
    })()
  };

  const formatDuration = (seconds: number): string => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    if (hours > 0) {
      return `${hours}h ${minutes}m`;
    }
    return `${minutes}m`;
  };

  const handlePresetSelect = (preset: AudioPreset) => {
    updateSettings({
      carrierFrequency: preset.carrierFrequency,
      beatFrequency: preset.beatFrequency,
      waveform: preset.waveform,
      mode: preset.mode,
      volume: settings.volume
    });
    setShowPresets(false);
    if (isIOS) {
      Haptics.impact({ style: ImpactStyle.Medium }).catch(() => {});
    }
  };

  const handleUpgrade = (tier: 'monthly' | 'annual' | 'lifetime') => {
    premiumService.setTier(tier);
    setShowPremiumModal(false);
    if (isIOS) {
      Haptics.notification({ type: NotificationType.Success }).catch(() => {});
    }
  };

  return (
    <>
      <div className="flex flex-col h-full bg-gradient-to-b from-indigo-900 via-purple-900 to-indigo-900 p-4 sm:p-6 safe-area-inset overflow-y-auto">
        {/* Header */}
        <div className="mb-6">
          <h1 className="text-2xl sm:text-3xl font-bold text-white mb-2">Profile</h1>
          <p className="text-purple-200 text-sm">Settings and preferences</p>
        </div>

        {/* Premium Status */}
        <div className="bg-white/10 backdrop-blur-lg rounded-2xl p-4 sm:p-6 border border-white/20 mb-4">
          <div className="flex items-center justify-between mb-4">
            <div>
              <h2 className="text-lg sm:text-xl font-bold text-white mb-1">
                {isPremium ? '⭐ Premium Member' : 'Free Account'}
              </h2>
              <p className="text-purple-200 text-sm">
                {isPremium ? 'Thank you for your support!' : 'Upgrade to unlock all features'}
              </p>
            </div>
            {!isPremium && (
              <button
                onClick={() => setShowPremiumModal(true)}
                className="px-4 py-2 bg-gradient-to-r from-yellow-500 to-orange-500 text-white rounded-lg font-semibold text-sm active:scale-95 transition-transform"
              >
                Upgrade
              </button>
            )}
          </div>
        </div>

        {/* Statistics */}
        <div className="grid grid-cols-2 gap-3 sm:gap-4 mb-4">
          <div className="bg-white/10 backdrop-blur-lg rounded-xl p-4 text-center border border-white/20">
            <div className="text-2xl sm:text-3xl font-bold text-white mb-1">{stats.totalSessions}</div>
            <div className="text-xs sm:text-sm text-purple-200">Total Sessions</div>
          </div>
          <div className="bg-white/10 backdrop-blur-lg rounded-xl p-4 text-center border border-white/20">
            <div className="text-2xl sm:text-3xl font-bold text-green-400 mb-1">{stats.completedSessions}</div>
            <div className="text-xs sm:text-sm text-purple-200">Completed</div>
          </div>
          <div className="bg-white/10 backdrop-blur-lg rounded-xl p-4 text-center border border-white/20">
            <div className="text-2xl sm:text-3xl font-bold text-blue-400 mb-1">{formatDuration(stats.totalDuration)}</div>
            <div className="text-xs sm:text-sm text-purple-200">Total Time</div>
          </div>
          <div className="bg-white/10 backdrop-blur-lg rounded-xl p-4 text-center border border-white/20">
            <div className="text-2xl sm:text-3xl font-bold text-yellow-400 mb-1">
              {stats.averageRating > 0 ? stats.averageRating.toFixed(1) : '—'}
            </div>
            <div className="text-xs sm:text-sm text-purple-200">Avg Rating</div>
          </div>
        </div>

        {/* Quick Actions */}
        <div className="space-y-3 mb-4">
          <button
            onClick={() => setShowHistory(true)}
            className="w-full bg-white/10 backdrop-blur-lg rounded-xl p-4 border border-white/20 flex items-center justify-between active:scale-[0.98] transition-transform"
          >
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-gradient-to-r from-blue-500 to-purple-600 flex items-center justify-center">
                <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
                </svg>
              </div>
              <div className="text-left">
                <h3 className="text-white font-semibold">Session History</h3>
                <p className="text-purple-200 text-xs">View all your sessions</p>
              </div>
            </div>
            <svg className="w-5 h-5 text-purple-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
            </svg>
          </button>

          <button
            onClick={() => setShowPresets(!showPresets)}
            className="w-full bg-white/10 backdrop-blur-lg rounded-xl p-4 border border-white/20 flex items-center justify-between active:scale-[0.98] transition-transform"
          >
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-gradient-to-r from-purple-500 to-pink-600 flex items-center justify-center">
                <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" />
                </svg>
              </div>
              <div className="text-left">
                <h3 className="text-white font-semibold">Audio Presets</h3>
                <p className="text-purple-200 text-xs">Quick-start configurations</p>
              </div>
            </div>
            <svg className={`w-5 h-5 text-purple-300 transition-transform ${showPresets ? 'rotate-90' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
            </svg>
          </button>
        </div>

        {/* Audio Presets */}
        {showPresets && (
          <div className="bg-white/10 backdrop-blur-lg rounded-xl p-4 border border-white/20 mb-4">
            <h3 className="text-white font-semibold mb-3">Select Preset</h3>
            <div className="grid grid-cols-2 gap-2 max-h-64 overflow-y-auto">
              {AUDIO_PRESETS.map(preset => {
                const isActive = 
                  Math.abs(settings.carrierFrequency - preset.carrierFrequency) < 1 &&
                  Math.abs(settings.beatFrequency - preset.beatFrequency) < 0.1 &&
                  settings.waveform === preset.waveform &&
                  settings.mode === preset.mode;

                return (
                  <button
                    key={preset.id}
                    onClick={() => handlePresetSelect(preset)}
                    className={`p-3 rounded-lg text-left border-2 transition-all ${
                      isActive
                        ? 'border-purple-500 bg-purple-500/20'
                        : 'border-white/20 bg-white/5 hover:border-white/40'
                    }`}
                  >
                    <div className="text-white font-medium text-sm mb-1">{preset.name}</div>
                    <div className="text-purple-200 text-xs">{preset.targetBrainwave}</div>
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* Settings */}
        <div className="bg-white/10 backdrop-blur-lg rounded-xl p-4 border border-white/20 mb-4">
          <h3 className="text-white font-semibold mb-4">Audio Settings</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-sm text-purple-200 mb-2">Volume</label>
              <div className="flex items-center gap-3">
                <input
                  type="range"
                  min="0"
                  max="1"
                  step="0.01"
                  value={settings.volume}
                  onChange={(e) => {
                    updateSettings({ ...settings, volume: parseFloat(e.target.value) });
                    if (isIOS) {
                      Haptics.impact({ style: ImpactStyle.Light }).catch(() => {});
                    }
                  }}
                  className="flex-1 h-2 bg-white/20 rounded-lg appearance-none accent-purple-500"
                />
                <span className="text-white font-medium text-sm min-w-[3rem] text-right">
                  {Math.round(settings.volume * 100)}%
                </span>
              </div>
            </div>
          </div>
        </div>

        {/* App Info */}
        <div className="text-center text-purple-200 text-xs mt-auto pt-4">
          <p>Blue Star Beats v0.0.0</p>
          <p className="mt-1">Precision Brainwave Entrainment</p>
        </div>
      </div>

      {showHistory && (
        <SessionHistory
          onClose={() => setShowHistory(false)}
        />
      )}

      {showPremiumModal && (
        <PremiumModal
          onClose={() => setShowPremiumModal(false)}
          onUpgrade={handleUpgrade}
        />
      )}
    </>
  );
};

export default ProfileView;

