import { useState, useEffect, useCallback, useRef } from 'react';
import { audioEngine } from '../lib/audioEngine';
import { SessionProtocol, SessionLength } from '../lib/sessionProtocols';
import { AudioSettings } from '../lib/types';
import { userPreferences } from '../lib/userPreferences';

export type TabType = 'home' | 'sessions' | 'history' | 'profile';

export const useAppState = () => {
  const [activeTab, setActiveTab] = useState<TabType>('home');
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentSession, setCurrentSession] = useState<SessionProtocol | null>(null);
  const [sessionLength, setSessionLength] = useState<SessionLength | null>(null);
  const [settings, setSettings] = useState<AudioSettings>({
    carrierFrequency: 200,
    beatFrequency: 10,
    volume: 0.7,
    waveform: 'sine',
    mode: 'binaural'
  });
  const sessionStartTimeRef = useRef<number | null>(null);

  // Initialize audio engine
  useEffect(() => {
    const initAudio = async () => {
      try {
        audioEngine.initAudioContext();
        audioEngine.setVolume(settings.volume);
      } catch (error) {
        console.error('Failed to initialize audio engine:', error);
      }
    };

    initAudio();

    return () => {
      audioEngine.stop();
    };
  }, []);

  const updateSettings = useCallback((newSettings: Partial<AudioSettings>) => {
    const updated = { ...settings, ...newSettings };
    setSettings(updated);

    if (newSettings.volume !== undefined) {
      audioEngine.setVolume(newSettings.volume);
    }
    if (newSettings.mode !== undefined) {
      audioEngine.setMode(newSettings.mode);
    }
    if (newSettings.waveform !== undefined) {
      audioEngine.setWaveform(newSettings.waveform);
    }
    if (newSettings.carrierFrequency !== undefined || newSettings.beatFrequency !== undefined) {
      audioEngine.updateFrequencies(
        updated.carrierFrequency,
        updated.beatFrequency
      );
    }
  }, [settings]);

  const togglePlayback = useCallback(async () => {
    if (isPlaying) {
      audioEngine.stop();
      setIsPlaying(false);
      sessionStartTimeRef.current = null;
    } else if (currentSession) {
      try {
        // Ensure settings are synchronized before start
        audioEngine.setVolume(settings.volume);
        audioEngine.setMode(settings.mode);
        audioEngine.setWaveform(settings.waveform);
        audioEngine.updateFrequencies(settings.carrierFrequency, settings.beatFrequency);

        await audioEngine.start();
        setIsPlaying(true);
        sessionStartTimeRef.current = Date.now();
        userPreferences.addToRecentlyPlayed(currentSession.id);
      } catch (error) {
        console.error('Failed to start audio:', error);
      }
    }
  }, [isPlaying, currentSession, settings]);

  const selectSession = useCallback((session: SessionProtocol, length: SessionLength) => {
    setCurrentSession(session);
    setSessionLength(length);

    const newSettings: AudioSettings = {
      mode: session.mode,
      waveform: session.waveform,
      carrierFrequency: session.carrierFrequency,
      beatFrequency: session.beatFrequency,
      volume: settings.volume
    };

    updateSettings(newSettings);
    setActiveTab('home');
  }, [settings.volume, updateSettings]);

  const handleSessionComplete = useCallback(() => {
    audioEngine.stop();
    setIsPlaying(false);

    // Track session completion
    if (currentSession && sessionLength && sessionStartTimeRef.current) {
      const actualDuration = Math.floor((Date.now() - sessionStartTimeRef.current) / 1000);
      const targetDuration = sessionLength * 60;
      const completed = actualDuration >= targetDuration * 0.8;

      userPreferences.addSessionHistory({
        sessionId: currentSession.id,
        date: new Date(),
        duration: actualDuration,
        completed,
        effectivenessRating: undefined,
        notes: undefined
      });
    }

    sessionStartTimeRef.current = null;
  }, [currentSession, sessionLength]);

  return {
    activeTab,
    setActiveTab,
    isPlaying,
    currentSession,
    sessionLength,
    settings,
    audioEngine,
    togglePlayback,
    updateSettings,
    selectSession,
    handleSessionComplete,
    setCurrentSession
  };
};

userPreferences.ts.content:
import { UserPreferences, SessionHistoryEntry, SessionLength } from './types';

const PREFERENCES_STORAGE_KEY = 'bluestarbeats_user_preferences';
const HISTORY_STORAGE_KEY = 'bluestarbeats_session_history';
const MAX_HISTORY_ENTRIES = 100;
const MAX_RECENT_SESSIONS = 20;

export class UserPreferencesManager {
  private static instance: UserPreferencesManager;

  private constructor() {}

  static getInstance(): UserPreferencesManager {
    if (!UserPreferencesManager.instance) {
      UserPreferencesManager.instance = new UserPreferencesManager();
    }
    return UserPreferencesManager.instance;
  }

  getDefaultPreferences(): UserPreferences {
    return {
      favoriteSessions: [],
      recentlyPlayed: [],
      preferredSessionLength: 30,
      notificationSettings: {
        sessionReminders: false,
        completionAlerts: true
      },
      audioSettings: {
        defaultVolume: 0.3,
        defaultWaveform: 'sine',
        defaultMode: 'binaural'
      }
    };
  }

  loadPreferences(): UserPreferences {
    try {
      const saved = localStorage.getItem(PREFERENCES_STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        // Merge with defaults to handle missing fields
        return { ...this.getDefaultPreferences(), ...parsed };
      }
    } catch (error) {
      console.error('Failed to load user preferences:', error);
    }
    return this.getDefaultPreferences();
  }

  savePreferences(preferences: UserPreferences): void {
    try {
      localStorage.setItem(PREFERENCES_STORAGE_KEY, JSON.stringify(preferences));
    } catch (error) {
      console.error('Failed to save user preferences:', error);
    }
  }

  addFavorite(sessionId: string): void {
    const prefs = this.loadPreferences();
    if (!prefs.favoriteSessions.includes(sessionId)) {
      prefs.favoriteSessions.push(sessionId);
      this.savePreferences(prefs);
    }
  }

  removeFavorite(sessionId: string): void {
    const prefs = this.loadPreferences();
    prefs.favoriteSessions = prefs.favoriteSessions.filter(id => id !== sessionId);
    this.savePreferences(prefs);
  }

  isFavorite(sessionId: string): boolean {
    const prefs = this.loadPreferences();
    return prefs.favoriteSessions.includes(sessionId);
  }

  addToRecentlyPlayed(sessionId: string): void {
    const prefs = this.loadPreferences();
    // Remove if already exists
    prefs.recentlyPlayed = prefs.recentlyPlayed.filter(id => id !== sessionId);
    // Add to beginning
    prefs.recentlyPlayed.unshift(sessionId);
    // Keep only the most recent
    prefs.recentlyPlayed = prefs.recentlyPlayed.slice(0, MAX_RECENT_SESSIONS);
    this.savePreferences(prefs);
  }

  getRecentlyPlayed(): string[] {
    const prefs = this.loadPreferences();
    return prefs.recentlyPlayed;
  }

  addSessionHistory(entry: SessionHistoryEntry): void {
    try {
      const history = this.getSessionHistory();
      history.unshift(entry);
      // Keep only the most recent entries
      const trimmed = history.slice(0, MAX_HISTORY_ENTRIES);
      localStorage.setItem(HISTORY_STORAGE_KEY, JSON.stringify(trimmed));
    } catch (error) {
      console.error('Failed to save session history:', error);
    }
  }

  getSessionHistory(): SessionHistoryEntry[] {
    try {
      const saved = localStorage.getItem(HISTORY_STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        // Convert date strings back to Date objects
        return parsed.map((entry: any) => ({
          ...entry,
          date: new Date(entry.date)
        }));
      }
    } catch (error) {
      console.error('Failed to load session history:', error);
    }
    return [];
  }

  getSessionStats(sessionId: string): { count: number; averageRating?: number } {
    const history = this.getSessionHistory();
    const sessions = history.filter(entry => entry.sessionId === sessionId);
    const completed = sessions.filter(s => s.completed);
    const ratings = completed
      .map(s => s.effectivenessRating)
      .filter((r): r is number => r !== undefined);

    return {
      count: completed.length,
      averageRating: ratings.length > 0 
        ? ratings.reduce((sum, r) => sum + r, 0) / ratings.length 
        : undefined
    };
  }

  updatePreferredSessionLength(length: SessionLength): void {
    const prefs = this.loadPreferences();
    prefs.preferredSessionLength = length;
    this.savePreferences(prefs);
  }

  updateDefaultAudioSettings(settings: Partial<UserPreferences['audioSettings']>): void {
    const prefs = this.loadPreferences();
    prefs.audioSettings = { ...prefs.audioSettings, ...settings };
    this.savePreferences(prefs);
  }

  updateNotificationSettings(settings: Partial<UserPreferences['notificationSettings']>): void {
    const prefs = this.loadPreferences();
    prefs.notificationSettings = { ...prefs.notificationSettings, ...settings };
    this.savePreferences(prefs);
  }
}

export const userPreferences = UserPreferencesManager.getInstance();

types.ts.content:
// Enhanced type definitions for Blue Star Beats

export type BrainwaveType = 'delta' | 'theta' | 'alpha' | 'beta' | 'gamma';
export type SessionCategory = 'sleep' | 'focus' | 'meditation' | 'anxiety' | 'creativity' | 'learning';
export type WaveformType = 'sine' | 'square' | 'triangle' | 'sawtooth';
export type AudioMode = 'binaural' | 'isochronic';
export type GoalType = 'sleep' | 'anxiety' | 'focus' | 'meditation';
export type SessionLength = 5 | 10 | 15 | 20 | 30 | 45 | 60 | 90 | 120;
export type Intensity = 'gentle' | 'moderate' | 'intense';

export interface FrequencyRamp {
  start: number;
  end: number;
  duration: number; // in seconds
}

export interface AudioSettings {
  carrierFrequency: number;
  beatFrequency: number;
  waveform: WaveformType;
  mode: AudioMode;
  volume: number;
}

export interface AudioPreset {
  id: string;
  name: string;
  carrierFrequency: number;
  beatFrequency: number;
  waveform: WaveformType;
  mode: AudioMode;
  description: string;
  targetBrainwave: BrainwaveType;
  intensity: Intensity;
  category: SessionCategory;
}

export interface SessionProtocol {
  id: string;
  name: string;
  description: string;
  goal: GoalType;
  category?: SessionCategory;
  brainwaveTarget?: BrainwaveType;
  lengths: SessionLength[];
  carrierFrequency: number;
  beatFrequency: number;
  waveform: WaveformType;
  mode: AudioMode;
  isPremium: boolean;
  frequencyRamp?: FrequencyRamp;
  intensity?: Intensity;
  createdAt?: Date;
  updatedAt?: Date;
  version?: number;
}

export interface SessionHistoryEntry {
  sessionId: string;
  date: Date;
  duration: number;
  completed: boolean;
  effectivenessRating?: number;
  notes?: string;
}

export interface UserPreferences {
  favoriteSessions: string[];
  recentlyPlayed: string[];
  preferredSessionLength: SessionLength;
  notificationSettings: {
    sessionReminders: boolean;
    completionAlerts: boolean;
  };
  audioSettings: {
    defaultVolume: number;
    defaultWaveform: WaveformType;
    defaultMode: AudioMode;
  };
}

export interface EnhancedSessionProtocol extends SessionProtocol {
  category: SessionCategory;
  tags: string[];
  estimatedEffectiveness: number; // 1-10 scale
  userRating?: number;
  completionCount?: number;
}
